def fail(message: str) -> None:
    REPORT_PATH.write_text("FAILED_178_STATS_APPROVED_CARD_BLOCK\n" + message + "\n", encoding="utf-8")
    raise SystemExit(message)


def backup_file(path: Path, ts: str) -> None:
    if path.exists():
        rel = path.relative_to(ROOT)
        target = BACKUP_DIR / rel.parent / f"{rel.name}.before_v178_{ts}"
        target.parent.mkdir(parents=True, exist_ok=True)
        shutil.copy2(path, target)


def main() -> None:
    if not PARTIAL_PATH.exists():
        fail(f"Missing partial: {PARTIAL_PATH}")
    if not CSS_PATH.exists():
        fail(f"Missing CSS: {CSS_PATH}")
    if not ASSISTS_SRC.exists():
        fail(f"Missing payload assists icon: {ASSISTS_SRC}")

    ts = datetime.now().strftime("%Y%m%d_%H%M%S")
    BACKUP_DIR.mkdir(exist_ok=True)

    backup_file(PARTIAL_PATH, ts)
    backup_file(CSS_PATH, ts)
    backup_file(ASSISTS_DST, ts)

    PARTIAL_PATH.write_text(PARTIAL_CONTENT, encoding="utf-8")

    css = CSS_PATH.read_text(encoding="utf-8")
    if MARKER not in css:
        CSS_PATH.write_text(css.rstrip() + CSS_BLOCK + "\n", encoding="utf-8")

    ASSISTS_DST.parent.mkdir(parents=True, exist_ok=True)
    shutil.copy2(ASSISTS_SRC, ASSISTS_DST)

    REPORT_PATH.write_text(
        "DONE_178_STATS_APPROVED_CARD_BLOCK\n"
        "changed=layouts/partials/transfer-player-stats.html\n"
        "changed=static/css/transfer-article.css\n"
        "changed=static/images/stats-icons/assists.png\n"
        "note=Replaces stats block with approved example #2 style: 3+2 icon cards, no visible values, hover tooltip with big number and label, assists icon is boot only. No market chart changes.\n",
        encoding="utf-8",
    )
    print("DONE_178_STATS_APPROVED_CARD_BLOCK")


if __name__ == "__main__":
    main()
